import{_ as a,o as p,c as t,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"饮血剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/饮血剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/饮血剑.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/饮血剑.md"};function o(d,e,l,_,i,c){return p(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"饮血剑",tabindex:"-1"},[b("饮血剑 "),r("a",{class:"header-anchor",href:"#饮血剑","aria-label":'Permalink to "饮血剑"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),n('<h1 id="饮血剑-1" tabindex="-1">饮血剑 <a class="header-anchor" href="#饮血剑-1" aria-label="Permalink to &quot;饮血剑&quot;">​</a></h1><p>长剑<br> 500<br> 武器伤害3L 破甲1<br> 武器体积3 力量需求3<br> 武器分类：剑<br> 伤害类型：物理挥砍</p><p>【锋利】：锋利异常，一无是处。</p><p>十字镐<br> D+750<br> 武器伤害6L 破甲1<br> 武器体积3 力量需求3<br> 武器分类：稿<br> 伤害类型：物理穿刺</p><p>能挖掘、敲碎厚实岩盘的大把十字镐。<br> 强壮挖石矿工们的武器。</p><p>原本的用途不是武器，<br> 但具有轻易凿穿铠甲的威力。</p><p>臭小鬼，难不成你比岩盘还厚？</p><p>【凿击】：十字镐的攻击额外具有【破甲5】效果，并且忽视对方的1点任意DR。</p><p>暴风大剑<br> D+1000<br> 武器伤害8L 重型武器 双手<br> 武器体积7 力量需求4<br> 武器分类：剑<br> 伤害类型：物理挥砍</p><p>由风暴之石打造而成的巨大武器，<br> 可以轻易的劈开敌人的护甲和防具。</p><p>在挥舞这把武器时，<br> 其会同时卷起致命的风暴。</p><p>【审判】：这把武器造成伤害的同时，会如同具有【融毁5】一样削减对方的防御。</p><p>吸血鬼节杖<br> 由长剑花费D+500升级而来<br> 武器伤害6L 破甲1<br> 武器体积3 力量需求3<br> 武器分类：杖<br> 伤害类型：物理钝击</p><p>吸血鬼男爵在嘬饮凡人鲜血时，<br> 用来免于弄脏手的器具。</p><p>其上弥漫着永不消去的浓烈铁锈味。</p><p>【吸血】：当你使用这把武器攻击时，如同具有【吸血2】一样结算。</p><p>饮血剑<br> 由暴风大剑+十字镐+吸血鬼节杖+D+500合成而来<br> C级武器<br> 武器伤害12L 破甲1<br> 武器体积6 力量需求3<br> 武器分类：剑<br> 伤害类型：亵渎</p><p>鲜血君王所配的长剑，<br> 反抗者将会被吸干血液，悬街示众。</p><p>在长剑的血泊中，王朝顷刻淹没，<br> 君王被溺死在自己的血液中。</p><p>至今其上的鲜血仍未干涸。</p><p>【渴血】：这把武器会占据持有者的1点意志力上限。<br> 由这把武器造成的伤害将会是由内而外的，因此造成亵渎伤害，<br> 这把武器额外具有【吸血2】，并且攻击额外具有【破甲5】效果，会如同具有【融毁5】一样削减对方的防御，并且忽视对方的1点任意DR。</p><p>【血海】：在战斗中，你可以消耗4点能量的同时消耗一个移动动作，使长剑在这个场景进入【饮血】状态，这会为你带来额外的【吸血3】</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',24)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
